"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { NAV_LINKS } from "@/lib/constants";
import MobileMenu from "./MobileMenu";

export default function Header() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 50);
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <>
      <header
        className={`fixed top-0 z-50 w-full transition-all duration-500 ${scrolled
          ? "bg-brand-navy/95 shadow-lg shadow-black/20 backdrop-blur-sm"
          : "bg-transparent"
          }`}
      >
        <div className="mx-auto flex h-20 max-w-7xl items-center justify-between px-6 lg:px-10">
          {/* Logo */}
          <Link href="/" className="relative shrink-0">
            <Image
              src="/images/logo/Artboard-1-400x400.png"
              alt="Le Pressoir Byzantin"
              width={52}
              height={52}
              priority
              className="transition-transform duration-300 hover:scale-105"
            />
          </Link>

          {/* Desktop nav */}
          <nav className="hidden items-center gap-8 lg:flex">
            {NAV_LINKS.map((link) => {
              const hasChildren = "children" in link && Array.isArray(link.children);

              return (
                <div key={link.label} className="group relative">
                  <Link
                    href={link.href}
                    className="relative font-medium tracking-wide text-brand-cream/80 transition-colors hover:text-brand-cream py-2"
                  >
                    {link.label}
                    <span className="absolute bottom-0 left-0 w-full h-px bg-brand-orange origin-left scale-x-0 transition-transform duration-300 group-hover:scale-x-100" />
                  </Link>

                  {hasChildren && (
                    <div className="pointer-events-none absolute left-1/2 top-full -translate-x-1/2 pt-3 opacity-0 transition-all duration-300 group-hover:pointer-events-auto group-hover:opacity-100">
                      <div className="min-w-[200px] rounded-sm border border-brand-orange/20 bg-brand-dark/95 p-2 shadow-[0_10px_30px_rgba(0,0,0,0.5)] backdrop-blur-md">
                        {(link as any).children.map((child: { href: string; label: string }) => (
                          <Link
                            key={child.href}
                            href={child.href}
                            className="block rounded-sm px-4 py-2.5 text-sm text-brand-cream/70 transition-colors hover:bg-brand-orange/10 hover:text-brand-orange"
                          >
                            {child.label}
                          </Link>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </nav>

          {/* Desktop CTA + Mobile hamburger */}
          <div className="flex items-center gap-4">
            <Link
              href="/reservation"
              className="hidden relative overflow-hidden rounded-sm border border-brand-orange bg-transparent px-5 py-2 text-sm font-heading tracking-widest text-brand-orange transition-all hover:text-brand-dark hover:shadow-[0_0_15px_rgba(251,143,44,0.4)] lg:block group"
            >
              <span className="absolute inset-0 bg-brand-orange translate-y-full transition-transform duration-300 ease-out group-hover:translate-y-0" />
              <span className="relative z-10 transition-colors duration-300 group-hover:text-brand-dark">RÉSERVER</span>
            </Link>

            <button
              onClick={() => setMobileOpen(true)}
              className="text-brand-cream lg:hidden"
              aria-label="Ouvrir le menu"
            >
              <svg
                width="26"
                height="26"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="1.5"
              >
                <path d="M3 8h18M3 16h18" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <MobileMenu open={mobileOpen} onClose={() => setMobileOpen(false)} />
    </>
  );
}
